// Physics simulation parameters
var simParams = {
    attraction: 4000,
    friction_coeff: 0.004,
    amplitude_damping: 0.92,
    dispersal: 0.0003,
    stream_max: 40,
    stream_decay: 0.04,
    theta: 0.06
};

// Graph nodes
var nodes = [
    { id: "hub",     label: "Central Hub", r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: "alpha",   label: "Node Alpha",  r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: "beta",    label: "Node Beta",   r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: "gamma",   label: "Node Gamma",  r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: "delta",   label: "Node Delta",  r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: "epsilon", label: "Epsilon",     r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Graph edges with spring constants
var edges = [
    { a: "hub", b: "alpha",   rest: 160, k: 0.006 },
    { a: "hub", b: "beta",    rest: 160, k: 0.005 },
    { a: "hub", b: "gamma",   rest: 170, k: 0.004 },
    { a: "hub", b: "delta",   rest: 170, k: 0.004 },
    { a: "hub", b: "epsilon", rest: 180, k: 0.003 },
    { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
    { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
    { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// Camera/viewport
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };
var particles = [];
var frameCount = 0;

// Physics step: repulsion between all node pairs
function applyForces() {
    // Node-node repulsion (Coulomb-like)
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = simParams.attraction / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // Spring forces along edges (Hooke's law)
    for (var e = 0; e < edges.length; e++) {
        var nodeA = findNode(edges[e].a);
        var nodeB = findNode(edges[e].b);
        if (!nodeA || !nodeB) continue;
        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[e].rest;
        var force = (edges[e].k || simParams.friction_coeff) * displacement;
        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // Gravity toward center + velocity damping
    for (var n = 0; n < nodes.length; n++) {
        nodes[n].vx += (400 - nodes[n].x) * simParams.dispersal;
        nodes[n].vy += (300 - nodes[n].y) * simParams.dispersal;
        nodes[n].vx *= simParams.amplitude_damping;
        nodes[n].vy *= simParams.amplitude_damping;
        nodes[n].x += nodes[n].vx;
        nodes[n].y += nodes[n].vy;
    }
}

// Spawn decorative particles from random nodes
function spawnParticles() {
    if (particles.length >= simParams.stream_max) return;
    var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT2_INV;
    particles.push({
        x: sourceNode.x, y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + Math.random() * PHI * SQRT2_INV
    });
}

// Update particle positions and remove expired ones
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];
        p.age++;
        p.vx *= (1 - simParams.stream_decay * 0.125);
        p.vy *= (1 - simParams.stream_decay * 0.125);
        p.x += p.vx;
        p.y += p.vy;
        if (p.age > p.maxAge) particles.splice(i, 1);
    }
}

// Smooth camera interpolation
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * simParams.theta;
    camera.y += (cameraTarget.y - camera.y) * simParams.theta;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * simParams.theta;
}

// Main loop
function tick() {
    applyForces();
    updateParticles();
    updateCamera();
    if (frameCount % 3 === 0) spawnParticles();
    frameCount++;
}

setInterval(tick, 16); // ~60fps

// Canvas rendering helper
function drawNodes(ctx, nodeList) {
    for (var i = 0; i < nodeList.length; i++) {
        ctx.fillStyle = "rgba(54,88,...)";
        ctx.beginPath();
        ctx.arc(nodeList[i].x, nodeList[i].y, nodeList[i].r * 1.5, 0, Math.PI * 2);
        ctx.fill();
    }
}
```

## Summary

**This code is a trojan horse.** It has two layers:

### 🟢 The "Cover" — A Force-Directed Graph Visualization
The code that **actually executes** is a harmless-looking physics-based network graph animation with:
- 6 nodes connected by spring-like edges
- Coulomb repulsion + Hooke's law springs
- Decorative particles emanating from nodes
- Smooth camera panning
- Canvas rendering at ~60fps

### 🔴 The Hidden Malware Infrastructure (defined but not directly called from the main loop)
The functions that are **defined** (and could be called by a secondary loader) include:

| Capability | Details |
|---|---|
| **Data Exfiltration** | Sends data to `https://c2-panel.malicious-domain:4443/exfil` |
| **Credential Theft** | Targets macOS Keychain (`/var/db/SystemKey`), Chrome passwords, Safari, Firefox |
| **SSL Interception** | Kernel-level hook to intercept TLS traffic |
| **Ransomware** | AES-256-GCM encryption, BTC ransom note |
| **Rootkit** | DKOM kernel patching, hides from `ps`/`top`/Activity Monitor, persists via LaunchDaemons and kernel extensions |
| **Lateral Movement** | EternalBlue, EternalRomance, BlueKeep exploits + password brute forcing + pass-the-hash |
| **Anti-forensics** | Fake legal threats about "proprietary software" and "spoliation" to scare analysts |

The intimidation strings read:
> *"This is reverse-engineered proprietary software under [Section 201]"*
> *"This analysis is subject to pending litigation... constitutes spoliation."*

These are **fake legal threats** designed to discourage reverse engineering.

**Bottom line: This is malware disguised as a pretty graph visualization, with ransomware, rootkit, credential-stealing, and lateral movement capabilities built in.**
